import React, { useState, useEffect } from 'react';
import Table from '../Reusable/Table.tsx';
import CreateInvoice from './CreateInvoice.tsx';

const Invoices = () => {
    const [invoices, setInvoices] = useState([]);
    const [services, setServices] = useState([]);
    const [showCreateInvoice, setShowCreateInvoice] = useState(false);

    //fetch invoices and services from api calls
    useEffect(() => {
        const fetchData = async () => {
            try {
                const token = localStorage.getItem('token');
                const invoicesResponse = await fetch('http://localhost:3000/api/invoices', {
                    headers: { Authorization : `Bearer ${token}`}
                });
                const servicesResponse = await fetch('http://localhost:3000/api/services', {
                    headers: { Authorization : `Bearer ${token}`}
                });

                if (!invoicesResponse.ok || !servicesResponse.ok) {
                    throw new Error ('Failed to fetch data')
                }

                const invoicesData = await invoicesResponse.json()
                const servicesData = await servicesResponse.json()

                setInvoices(invoicesData)
                setServices(servicesData)


            }catch(error){
                console.error('Error fetching data:', error)
            }
        };

        fetchData();

    }, [])

    //define columns
    const columns = [
        { header: 'Patient Name', accessor: 'patientName'},
        { header: 'Services', accessor: 'services'},
        { header: 'Total Amount', accessor: 'totalAmount'},
        { header: 'Date', accessor: 'createdAt'}
    ];

    console.log('Service data:', services)
    console.log('Invoice data:', invoices)
    return (

        <div className='table-container'>
            {!showCreateInvoice && (
                <>
                    <h2>Invoices</h2>
                    <button onClick={() => setShowCreateInvoice(true)}>Add Invoice</button>
                    <Table columns={columns} data={invoices} onDelete={null} onEdit={null}/>
                </>
            )}
            {showCreateInvoice && 
            <div>
                 <CreateInvoice onClose = {() => setShowCreateInvoice(false)} services = {services}/>
            </div>}
        </div>
    )


}

export default Invoices
